142	    func controlBleHandlerLife(address: String?, cccVid: String?, isResuce: Bool = false) {
143	        guard let presenter = self.presenter else {
144	            Log.i(tag: "bleLife", "presenter为nil,return")
145	            return
146	        }
147	        let cccVid = cccVid ?? presenter.vehiclePreference.extInfo?.cccVid
148	        let category = BLEHandlerFactory.bleCreateCategory(presenter: presenter)
149	        
150	        guard category != .NONE else {
151	            Log.i(tag: "bleLife", "category is none, remove old")
152	            self.removeOriginBleHandler()
153	            self.bleCategory = .NONE
154	            self.tboxRunException = false
155	            return
156	        }
157	        Log.i(tag: "bleLife", "category is \(category)")
158	        if self.bleCategory != category {
159	            self.removeOriginBleHandler()
160	            self.cleanBleInfoCache()
161	            self.getVaildKeySettingData()
162	        }
163	        if self.tboxRunException != isResuce {
164	            self.removeOriginBleHandler()
165	            self.tboxRunException = isResuce
166	        }
167	        
168	        guard let oldHandler = self.bleHandler else {
169	            Log.i(tag: "bleLife", "old ble handler is nil")
170	            guard let bleHandler = BLEHandlerFactory.createBleKeyHandler(macAddress: address, cccVid: cccVid, bleCategory: category, delegate: self, presenter: presenter, isResuce: isResuce) else {
171	                Log.i(tag: "bleLife", "create ble handler failed, return")
172	                return
173	            }
174	            return self.createNewBleHandler(bleHandler: bleHandler, bleCategory: category, presenter: presenter)
175	        }
176	        Log.i(tag: "bleLife", "old ble handler is not nil")
177	        if category != .PHONE_UWB_KEY {
178	            guard let macAddress = address else {
179	                Log.i(tag: "bleLife", "address is nil,remove origin")
180	                self.removeOriginBleHandler()
181	                return
182	            }
183	            if oldHandler.macAddress == macAddress {
184	                Log.i(tag: "bleLife", "old ble handler address is same to macAddress")
185	                return
186	            }
187	            Log.i(tag: "bleLife", "address is not same,remove origin")
188	            guard let bleHandler = BLEHandlerFactory.createBleKeyHandler(macAddress: address, cccVid: cccVid, bleCategory: category, delegate: self, presenter: presenter, isResuce: isResuce) else {
189	                Log.i(tag: "bleLife", "create ble handler failed, return")
190	                return
191	            }
192	            return self.createNewBleHandler(bleHandler: bleHandler, bleCategory: category, presenter: presenter)
193	        } else {
194	            if BLEHandlerFactory.carKeyCCCVidIsChanged(bleHandler: oldHandler, cccVid: cccVid) == false {
195	                Log.i(tag: "bleLife", "old ble handler cccVid is same to cccVid")
196	                return
197	            } else {
198	                Log.i(tag: "bleLife", "old ble handler cccVid is not same to cccVid")
199	                self.removeOriginBleHandler()
200	                guard let bleHandler = BLEHandlerFactory.createBleKeyHandler(macAddress: address, cccVid: cccVid, bleCategory: category, delegate: self, presenter: presenter, isResuce: isResuce) else {
201	                    Log.i(tag: "bleLife", "create ble handler failed, return")
202	                    return
203	                }
204	                return self.createNewBleHandler(bleHandler: bleHandler, bleCategory: category, presenter: presenter)
205	            }
206	            return
207	        }
208	    }
