    @objc func refreshDigitalKeyFromNotification(noti: Notification) {
        let code: Int = noti.userInfo?["code"] as? Int ?? 0
        switch code {
        case 0xF2:  // 钥匙已拉黑
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.ban.rawValue])
            break
        case 0xF3:  // 钥匙激活超过一天有效期
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.oneDay.rawValue])
            break
        case 0xF4:  // vin校验不对
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.vin.rawValue])
            break
        case 0xF5:  // 钥匙过期（使用期限）
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.disabled.rawValue])
            break
        case 0xF6:  // 钥匙已满
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.full.rawValue])
            break
        case 0xF7:  // 钥匙信息签名校验不通过
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.otherError.rawValue])
            break
        case 0xF8:  // 钥匙信息不匹配
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.otherError.rawValue])
            break
        default:
            break
        }
        self.requestRemoteKeyList(isFromInit: false)
    }

    //MonaKeyStatusDelegate
    func onBleKeyChange(type: KeyChangeType, key: BleKeyInfo?) {
        switch type {
        case KeyChangeType.activate:
            if self.existValidBlePrivateKey() == true {
                return;
            }
            let card: BLEKeyCard = BLEKeyCard.init()
            card.cardType = KeyCardType.MONA_BLE
            card.status = XPBLEKeyCardStatus.XPBLEKeyCardStatusNormal;
            card.vin = key?.vin
            self.dealWithRemoteKeys(cards: [card], isFromInit: false, localBleInfoOutsideSDK: nil, noBioVerify: nil, doublesidedAuthCode: nil)
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.activate.rawValue])
            break
        case KeyChangeType.delete:
            if self.existValidBlePrivateKey() == false {
                return;
            }
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.delete.rawValue])
            break
        case KeyChangeType.create:
            if self.existValidBlePrivateKey() == true {
                return;
            }
            NotificationCenter.default.post(name: VehicleNotification.DigitalKeyCreateKey, object: nil, userInfo: ["type": CreateKeyChangeType.create.rawValue])
            break
        default:
            break
        }
    }

    public static func downloadDigitalKeyList(uid: UInt64!, vehicle: VehicleInfo.Vehicle!, keyTypeList: [Int], vehiclePreference: VehiclePreference!) {
        let digitalKeyList = DigitalKey.queryDigitalKeyList(vin: vehicle.vin ?? "")
        if digitalKeyList.count > 0 {
            for digitalKey in digitalKeyList {
                downloadKeyMessagesCheck(digitalKey: digitalKey, vehicle: vehicle)
            }
        } else {
            var keyCardType: KeyCardType = .NONE
            if allowCallMonaSDK(vehiclePreference: vehiclePreference) {
                keyCardType = KeyCardType.MONA_BLE
            } else if vehiclePreference.abilityConfig.bleKeyVersion == BleKeyProtocolVesion.V3 {
                keyCardType = KeyCardType.SELF_V3
            } else if let pluginSelf = generatePlugin(uid: uid, keyCardType: KeyCardType.SELF, vehicle: vehicle) {
                keyCardType = KeyCardType.SELF
            }
            if DigitalKeyManager.staticPlugin[DigitalKeyManager.pluginKey(uid: uid, vin: vehicle.vin ?? "", keyCardType: keyCardType)] != nil {
                return;
            }
            Log.i(tag:"DigitalKeyManager", "其他车辆数字钥匙开始预加载 \(uid ?? 0) \(vehicle.vin ?? "")")
            DigitalKeyManager.requestDigitalKeyList(uid: uid, vehicle: vehicle, vin: vehicle.vin ?? "", vehiclePreference: vehiclePreference){ data in
                let list: [BLEKeyCard]! = data?.cardList ?? []
                for remoteKey in list {
                    let digitalKey = DigitalKey(bleKeyCard: remoteKey, uid:uid, vin: remoteKey.vin ?? "", keyCardType: remoteKey.cardType ?? KeyCardType.NONE, cardNo: remoteKey.cardNo)
                    digitalKey.bleKeyCard = remoteKey
                    digitalKey.save()
                    downloadKeyMessagesCheck(digitalKey: digitalKey, vehicle: vehicle)
                }
            } failed: { error in

            }
        }
    }

    static func requestDigitalKeyList(uid: UInt64!, vehicle: VehicleInfo.Vehicle!, vin: String, vehiclePreference: VehiclePreference!, success: @escaping VehicleDigitalKeySuccessResponseCallback<RequestDigitalKeyListResponse>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        if allowCallMonaSDK(vehiclePreference: vehiclePreference) {
            if let pluginMona = generatePlugin(uid: uid, keyCardType: KeyCardType.MONA_BLE, vehicle: vehicle) {
                setCachePlugin(plugin: pluginMona, uid: uid, vin: vin, keyCardType: KeyCardType.MONA_BLE)
                pluginMona.requestCardListOwn(vin: vin ?? "", uid: uid ?? 0) { response in
                    let res = RequestDigitalKeyListResponse()
                    if let data: RequestCardListResponse = response.data {
                        res.cardList = data.cardList
                    }
                    setCachePlugin(plugin: nil, uid: uid, vin: vin, keyCardType: KeyCardType.MONA_BLE)
                    success(res)
                    Log.i(tag:"DigitalKeyManager", "拉取钥匙列表成功")
                }
            }
        } else if vehiclePreference.abilityConfig.bleKeyVersion == BleKeyProtocolVesion.V3 {
            if let pluginSelfV3 = generatePlugin(uid: uid, keyCardType: KeyCardType.SELF_V3, vehicle: vehicle) {
                setCachePlugin(plugin: pluginSelfV3, uid: uid, vin: vin, keyCardType: KeyCardType.SELF_V3)


                self.requestNomalList(pluginSelf: pluginSelfV3, needRequestEmpower: false, uid: uid, vin: vin, success: { data in
                    setCachePlugin(plugin: nil, uid: uid, vin: vin, keyCardType: KeyCardType.SELF_V3)
                    success(data)
                    Log.i(tag:"DigitalKeyManager", "拉取钥匙列表成功")

                }) { error in
                    setCachePlugin(plugin: nil, uid: uid, vin: vin, keyCardType: KeyCardType.SELF_V3)
                    failed(error)
                    Log.i(tag:"DigitalKeyManager", "拉取钥匙列表失败")
                }
            }
        } else if let pluginSelf = generatePlugin(uid: uid, keyCardType: KeyCardType.SELF, vehicle: vehicle) {
            setCachePlugin(plugin: pluginSelf, uid: uid, vin: vin, keyCardType: KeyCardType.SELF)
            self.requestNomalList(pluginSelf: pluginSelf, needRequestEmpower:true, uid: uid, vin: vin, success: { data in
                setCachePlugin(plugin: nil, uid: uid, vin: vin, keyCardType: KeyCardType.SELF)
                success(data)
            }) { error in
                setCachePlugin(plugin: nil, uid: uid, vin: vin, keyCardType: KeyCardType.SELF)
                failed(error)
            }
        } else {
            let resp = VehicleError(code: .UnknownError, msg:nil)
            failed(resp)
        }
    }

    static func requestNomalList(pluginSelf: DigitalKeyManagerPluginProtocol!, needRequestEmpower: Bool!, uid: UInt64!, vin:String, success: @escaping VehicleDigitalKeySuccessResponseCallback<RequestDigitalKeyListResponse>, failed: @escaping VehicleFailedCallback<VehicleError>){
        pluginSelf.requestCardListOwn(vin: vin ?? "", uid: uid ?? 0, callback: { response in
            if (response.code == 200) {
                let cardListOwn = response.data?.cardList
                guard needRequestEmpower == true else {
                    let res = RequestDigitalKeyListResponse()
                    res.cardList = cardListOwn
                    success(res)
                    return
                }
                self.requestEmpowerDigitalKeyList(cardlistOwn: cardListOwn, uid: uid, vin: vin, success: success, failed: failed)
            } else {
                guard needRequestEmpower == true else {
                    let resp = VehicleError(code: .UnknownError, desc:response.msg)
                    failed(resp)
                    return
                }
                self.requestEmpowerDigitalKeyList(cardlistOwn: [], uid: uid, vin: vin, success: success, failed: failed)
            }
        })
    }


    static func requestEmpowerDigitalKeyList(cardlistOwn: [BLEKeyCard]?, uid: UInt64!, vin: String, success: @escaping VehicleDigitalKeySuccessResponseCallback<RequestDigitalKeyListResponse>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        SelfKeyManager.requestCardListEmpower(vin: vin) { response in
            if (response.code == 200) {
                Log.i(tag:"DigitalKeyManager", "拉取被授权钥匙列表成功: \(String(describing: response.data))")
                let cardListEmpower = response.data?.cardList
                let res = RequestDigitalKeyListResponse()
                res.cardList = ((cardlistOwn ?? []) + (cardListEmpower ?? [])).filter { $0.cardType != KeyCardType.SAFE }
                success(res)
            } else {
                Log.i(tag:"DigitalKeyManager", "拉取被授权钥匙列表失败: \(String(describing: response.msg))")
                let resp = VehicleError(code: .UnknownError, desc:response.msg)
                failed(resp)
            }
        }
    }

    static func generatePlugin(uid: UInt64!, keyCardType: KeyCardType, vehicle: VehicleInfo.Vehicle!) -> DigitalKeyManagerPluginProtocol?{
        let aClass: AnyClass? = DigitalKeyManager.keyManagerMap[keyCardType] as? AnyClass
        guard let typeClass = aClass as? DigitalKeyManagerPluginBase.Type else {
            Log.i(tag:"DigitalKeyManager", "数字钥匙创建 \(keyCardType) DigitalKeyManagerPlugin 不存在或不符合要求")
            return nil
        }
        let plugin: DigitalKeyManagerPluginProtocol = typeClass.init(uid: uid, vehicle: vehicle, cardNo: nil) as! DigitalKeyManagerPluginProtocol
        return plugin
    }

    static func setCachePlugin(plugin: DigitalKeyManagerPluginProtocol?, uid: UInt64?, vin: String?, keyCardType: KeyCardType?){
        serialPluginQueue.async {
            let key = pluginKey(uid: uid, vin: vin, keyCardType: keyCardType)
            if key != nil && DigitalKeyManager.staticPlugin != nil {
                if plugin == nil {
                    DigitalKeyManager.staticPlugin.removeValue(forKey: key)
                } else {
                    DigitalKeyManager.staticPlugin[key] = plugin
                }
            }
        }
    }

    static func pluginKey(uid: UInt64?, vin: String?, keyCardType: KeyCardType?) -> String {
        return String(uid ?? 0) + (vin ?? "") + (String((keyCardType ?? KeyCardType.NONE).rawValue) ?? "")
    }

    static func downloadKeyMessagesCheck(digitalKey: DigitalKey, vehicle: VehicleInfo.Vehicle!) {
        if digitalKey.supportKeyMessage() == true{
            if digitalKey.keyMessageCount() == 0 {
                digitalKey.downloadKeyMessages(callBack: { isSuc in
                    macAddressCheck(digitalKey: digitalKey, vehicle: vehicle)
                })
            } else {
                macAddressCheck(digitalKey: digitalKey, vehicle: vehicle)
            }
        } else {
            macAddressCheck(digitalKey: digitalKey, vehicle: vehicle)
        }
    }

    static func macAddressCheck(digitalKey: DigitalKey, vehicle: VehicleInfo.Vehicle!) {
        if digitalKey.isNeedMacAddress() == false {
            return;
        }
        if let bleInfo = digitalKey.bleInfo {
            if bleInfo.macAddress != nil {
                return
            }
        }
        let responseCallback: BLEKeyHttpRequestCallback<BLEInfo> = { response in
            if (response.code == 200 && response.data != nil) {
                let info = response.data!
                let macAddress = (info.macAddress ?? "") as String
                Log.i(tag:"DigitalKeyManager", "预先下载到Mac地址 macAddress:", macAddress)
                if (vehicle.vehicleTypeCode != "ED") {
                    info.useScanUUIDs = true
                }
                digitalKey.bleInfo = info
                digitalKey.save()
            }
        }
        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.bleInfo, payload: ["vin": digitalKey.vin ?? ""], callback: responseCallback)
    }

    public func pollingStateChange(pollingMode: VehiclePollingMode) {
        if let xiaopengBleConnection = self.communication?.bleConnection as? XiaopengBLEConnection {
